rollTypes.handleResult:
if (data.roll?.metadata?.group && data.roll?.metadata?.group.length > 0) {
  data.roll?.metadata?.group.forEach((tokenId) => {
    api.setValueOnTokenById(
      tokenId,
      "tokens",
